     1→"use client";
     2→
     3→import { useState, Suspense } from "react";
     4→import { useSearchParams } from "next/navigation";
     5→import useSWR from "swr";
     6→import Link from "next/link";
     7→import {
     8→  releases as releasesApi,
     9→  projects as projectsApi,
    10→  sources as sourcesApi,
    11→} from "@/lib/api/client";
    12→import { ProviderBadge } from "@/components/ui/provider-badge";
    13→import { VersionChip } from "@/components/ui/version-chip";
    14→import type { Release, Source, Project } from "@/lib/api/types";
    15→import { ExternalLink } from "lucide-react";
    16→
    17→import { timeAgo } from "@/lib/format";
    18→
    19→interface ReleaseRow extends Release {
    20→  _projectName?: string;
    21→  _projectId?: string;
    22→  _provider?: string;
    23→  _repository?: string;
    24→}
    25→
    26→const PER_PAGE = 15;
    27→
    28→function getProviderUrl(
    29→  provider: string,
    30→  repository: string,
    31→  version: string
    32→): string | null {
    33→  switch (provider) {
    34→    case "github":
    35→      return `https://github.com/${repository}/releases/tag/${version}`;
    36→    case "dockerhub":
    37→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    38→    default:
    39→      return null;
    40→  }
    41→}
    42→
    43→/* ------------------------------------------------------------------ */
    44→/*  Page                                                               */
    45→/* ------------------------------------------------------------------ */
    46→
    47→export default function ReleasesPage() {
    48→  return (
    49→    <Suspense>
    50→      <ReleasesPageInner />
    51→    </Suspense>
    52→  );
    53→}
    54→
    55→function ReleasesPageInner() {
    56→  const searchParams = useSearchParams();
    57→  const initialProject = searchParams.get("project") ?? "all";
    58→  const [page, setPage] = useState(1);
    59→  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    60→
    61→  /* Fetch projects for the filter dropdown + source enrichment */
    62→  const { data: projectsData } = useSWR("projects-for-filter", () =>
    63→    projectsApi.list()
    64→  );
    65→
    66→  /* Build a map: sourceId -> { provider, repository, projectName, projectId } */
    67→  const { data: sourceMap } = useSWR(
    68→    projectsData ? "source-map-for-releases" : null,
    69→    async () => {
    70→      if (!projectsData?.data?.length) return new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
    71→      const map = new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
    72→      await Promise.all(
    73→        projectsData.data.map(async (p: Project) => {
    74→          const res = await sourcesApi.listByProject(p.id).catch(() => null);
    75→          if (res?.data) {
    76→            for (const s of res.data) {
    77→              map.set(s.id, {
    78→                provider: s.provider,
    79→                repository: s.repository,
    80→                projectName: p.name,
    81→                projectId: p.id,
    82→              });
    83→            }
    84→          }
    85→        })
    86→      );
    87→      return map;
    88→    }
    89→  );
    90→
    91→  /* Fetch releases — scoped by project or all */
    92→  const { data: scopedData, isLoading: scopedLoading } = useSWR(
    93→    projectFilter !== "all" ? ["releases", page, projectFilter] : null,
    94→    () => releasesApi.listByProject(projectFilter, page, PER_PAGE)
    95→  );
    96→
    97→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    98→    projectFilter === "all" ? ["all-releases", page] : null,
    99→    () => releasesApi.list(page, PER_PAGE)
   100→  );
   101→
   102→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
   103→
   104→  /* Enrich releases with source metadata */
   105→  const rawReleases: Release[] =
   106→    projectFilter !== "all"
   107→      ? scopedData?.data ?? []
   108→      : allReleasesData?.data ?? [];
   109→
   110→  const releases: ReleaseRow[] = rawReleases.map((r) => {
   111→    const info = sourceMap?.get(r.source_id);
   112→    return {
   113→      ...r,
   114→      _projectName: info?.projectName,
   115→      _projectId: info?.projectId,
   116→      _provider: info?.provider,
   117→      _repository: info?.repository,
   118→    };
   119→  });
   120→
   121→  /* Pagination math */
   122→  const activeData = projectFilter !== "all" ? scopedData : allReleasesData;
   123→  const total = activeData?.meta?.total ?? 0;
   124→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
   125→  const startRow = (page - 1) * PER_PAGE + 1;
   126→  const endRow = Math.min(page * PER_PAGE, total);
   127→
   128→  return (
   129→    <div className="space-y-6">
   130→      {/* Page title */}
   131→      <h1
   132→        style={{
   133→          fontFamily: "var(--font-fraunces)",
   134→          fontSize: "24px",
   135→          fontWeight: 700,
   136→          color: "#111113",
   137→        }}
   138→      >
   139→        Releases
   140→      </h1>
   141→
   142→      {/* Project filter */}
   143→      <div>
   144→        <select
   145→          value={projectFilter}
   146→          onChange={(e) => {
   147→            setProjectFilter(e.target.value);
   148→            setPage(1);
   149→          }}
   150→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   151→          style={{
   152→            fontFamily: "var(--font-dm-sans)",
   153→            fontSize: "13px",
   154→            color: "#111113",
   155→            border: "1px solid #e8e8e5",
   156→          }}
   157→          onFocus={(e) =>
   158→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   159→          }
   160→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   161→        >
   162→          <option value="all">All Projects</option>
   163→          {projectsData?.data.map((p: Project) => (
   164→            <option key={p.id} value={p.id}>
   165→              {p.name}
   166→            </option>
   167→          ))}
   168→        </select>
   169→      </div>
   170→
   171→      {/* Table card */}
