     5→const SEGMENT_LABELS: Record<string, string> = {
     6→  "": "Dashboard",
     7→  projects: "Projects",
     8→  releases: "Releases",
     9→  sources: "Sources",
    10→  subscriptions: "Subscriptions",
    11→  channels: "Channels",
