    35→function formatDuration(startedAt?: string, completedAt?: string): string {
    36→  if (!startedAt) return "--";
    37→  const start = new Date(startedAt).getTime();
    38→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    39→  const secs = Math.round((end - start) / 1000);
    40→  if (secs < 60) return `${secs}s`;
    41→  const mins = Math.floor(secs / 60);
    42→  const rem = secs % 60;
    43→  return `${mins}m ${rem}s`;
    44→}
    45→
    46→function truncate(str: string, max: number): string {
    47→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    48→}
    49→
    50→function formatInterval(seconds: number): string {
    51→  if (seconds < 60) return `${seconds}s`;
    52→  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    53→  return `${(seconds / 3600).toFixed(1)}h`;
    54→}
