    26→  const { data: allReleases, isLoading } = useSWR(
    27→    projectsData ? "recent-releases" : null,
    28→    async () => {
    29→      if (!projectsData?.data?.length) return [];
    30→
    31→      // Fetch releases and sources in parallel per project
    32→      const projectSlice = projectsData.data.slice(0, 10);
    33→      const [releaseResults, sourceResults] = await Promise.all([
    34→        Promise.all(
    35→          projectSlice.map((p) =>
    36→            releasesApi.listByProject(p.id, 1).catch(() => null)
    37→          )
    38→        ),
    39→        Promise.all(
    40→          projectSlice.map((p) =>
    41→            sourcesApi.listByProject(p.id, 1).catch(() => null)
    42→          )
    43→        ),
    44→      ]);
    45→
    46→      // Build source_id -> repository and source_id -> provider maps
    47→      const sourceMap = new Map<string, string>();
    48→      const providerMap = new Map<string, string>();
    49→      sourceResults
    50→        .filter((r): r is NonNullable<typeof r> => r !== null)
    51→        .flatMap((r) => r.data)
    52→        .forEach((s: Source) => {
    53→          sourceMap.set(s.id, s.repository);
