    56→
    57→      const releases: ReleaseRow[] = releaseResults
    58→        .filter((r): r is NonNullable<typeof r> => r !== null)
    59→        .flatMap((r) => r.data)
    60→        .sort(
    61→          (a, b) =>
    62→            new Date(b.released_at ?? b.created_at).getTime() - new Date(a.released_at ?? a.created_at).getTime()
    63→        )
