    65→        .map((rel) => ({
    66→          ...rel,
    67→          _repository: sourceMap.get(rel.source_id),
    68→          _provider: providerMap.get(rel.source_id),
    69→        }));
    70→
    71→      return releases;
    72→    }
    73→  );
