// web/lib/api/types.ts

// --- Response Envelope ---

export interface ApiResponse<T> {
  data: T;
  meta?: ApiMeta;
  error?: ApiError;
}

export interface ApiMeta {
  page: number;
  per_page: number;
  total: number;
}

export interface ApiError {
  code: string;
  message: string;
}

// --- Domain Models (all IDs are UUID strings) ---

export interface Project {
  id: string;
  name: string;
  description?: string;
  agent_prompt?: string;
  agent_rules?: AgentRules;
  created_at: string;
  updated_at: string;
}

export interface AgentRules {
  on_major_release?: boolean;
  on_minor_release?: boolean;
  on_security_patch?: boolean;
  version_pattern?: string;
}

export interface ProjectInput {
  name: string;
  description?: string;
  agent_prompt?: string;
  agent_rules?: AgentRules;
}

export interface Source {
  id: string;
  project_id: string;
  provider: string;
  repository: string;
  poll_interval_seconds: number;
  enabled: boolean;
  config?: Record<string, unknown>;
  last_polled_at?: string;
  last_error?: string;
  created_at: string;
  updated_at: string;
}

export interface SourceInput {
  provider: string;
  repository: string;
  poll_interval_seconds: number;
  enabled: boolean;
  config?: Record<string, unknown>;
}

export interface Release {
  id: string;
  source_id: string;
  version: string;
  raw_data?: Record<string, unknown>;
  released_at?: string;
  created_at: string;
}

export interface ContextSource {
  id: string;
  project_id: string;
  type: string;
  name: string;
  config: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface ContextSourceInput {
  type: string;
  name: string;
  config: Record<string, unknown>;
}

export interface SemanticRelease {
  id: string;
  project_id: string;
  version: string;
  report?: SemanticReport;
  status: string;
  error?: string;
  created_at: string;
  completed_at?: string;
}

export interface SemanticReport {
  summary: string;
  availability: string;
  adoption: string;
  urgency: string;
  recommendation: string;
}

export interface AgentRun {
  id: string;
  project_id: string;
  semantic_release_id?: string;
  trigger: string;
  status: string;
  prompt_used?: string;
  error?: string;
  started_at?: string;
  completed_at?: string;
  created_at: string;
}

export interface NotificationChannel {
  id: string;
  name: string;
  type: string;
  config: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface ChannelInput {
  type: string;
  name: string;
  config: Record<string, unknown>;
}

export interface Subscription {
  id: string;
  channel_id: string;
  type: "source" | "project";
  source_id?: string;
  project_id?: string;
  version_filter?: string;
  created_at: string;
}

export interface SubscriptionInput {
  channel_id: string;
  type: "source" | "project";
  source_id?: string;
  project_id?: string;
  version_filter?: string;
}

// --- System Types ---

export interface HealthStatus {
  status: string;
  database: string;
}

export interface Stats {
  total_projects: number;
  active_sources: number;
  total_releases: number;
  pending_agent_runs: number;
}

// --- SSE Event Types ---

export type SSEEventType = "release" | "semantic_release";

interface SSEBase {
  id: string;
  timestamp: string;
}

export type SSEEvent =
  | (SSEBase & {
      type: "release";
      data: { id: string; source_id: string; version: string; created_at: string };
    })
  | (SSEBase & {
      type: "semantic_release";
      data: { id: string; project_id: string; version: string; status: string };
    });

// web/lib/api/client.ts
import type {
  ApiResponse,
  Project,
  ProjectInput,
  Release,
  Source,
  SourceInput,
  Subscription,
  SubscriptionInput,
  NotificationChannel,
  ChannelInput,
  ContextSource,
  ContextSourceInput,
  SemanticRelease,
  AgentRun,
  HealthStatus,
  Stats,
} from "./types";

const BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    headers: { "Content-Type": "application/json", ...init?.headers },
    ...init,
  });
  if (!res.ok) {
    const body = await res.json().catch(() => null);
    throw new Error(body?.error?.message ?? `Request failed: ${res.status}`);
  }
  if (res.status === 204) return null as T;
  return res.json();
}

// --- Projects ---

export const projects = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Project[]>>(`/projects?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Project>>(`/projects/${id}`),
  create: (input: ProjectInput) =>
    request<ApiResponse<Project>>("/projects", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: ProjectInput) =>
    request<ApiResponse<Project>>(`/projects/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/projects/${id}`, { method: "DELETE" }),
};

// --- Sources (nested under projects) ---

export const sources = {
  listByProject: (projectId: string, page = 1) =>
    request<ApiResponse<Source[]>>(`/projects/${projectId}/sources?page=${page}`),
  create: (projectId: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/projects/${projectId}/sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<Source>>(`/sources/${id}`),
  update: (id: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/sources/${id}`, { method: "DELETE" }),
};

// --- Releases ---

export const releases = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/releases?page=${page}&per_page=${perPage}`),
  listBySource: (sourceId: string, page = 1) =>
    request<ApiResponse<Release[]>>(`/sources/${sourceId}/releases?page=${page}`),
  listByProject: (projectId: string, page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/projects/${projectId}/releases?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Release>>(`/releases/${id}`),
};

// --- Context Sources ---

export const contextSources = {
  list: (projectId: string, page = 1) =>
    request<ApiResponse<ContextSource[]>>(`/projects/${projectId}/context-sources?page=${page}`),
  create: (projectId: string, input: ContextSourceInput) =>
    request<ApiResponse<ContextSource>>(`/projects/${projectId}/context-sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<ContextSource>>(`/context-sources/${id}`),
  update: (id: string, input: ContextSourceInput) =>
    request<ApiResponse<ContextSource>>(`/context-sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/context-sources/${id}`, { method: "DELETE" }),
};

// --- Semantic Releases ---

export const semanticReleases = {
  listAll: (page = 1, perPage = 25) =>
    request<ApiResponse<SemanticRelease[]>>(`/semantic-releases?page=${page}&per_page=${perPage}`),
  list: (projectId: string, page = 1, perPage = 25) =>
    request<ApiResponse<SemanticRelease[]>>(`/projects/${projectId}/semantic-releases?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<SemanticRelease>>(`/semantic-releases/${id}`),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/semantic-releases/${id}`, { method: "DELETE" }),
};

// --- Agent ---

export const agent = {
  triggerRun: (projectId: string) =>
    request<ApiResponse<AgentRun>>(`/projects/${projectId}/agent/run`, { method: "POST", body: "{}" }),
  listRuns: (projectId: string, page = 1) =>
    request<ApiResponse<AgentRun[]>>(`/projects/${projectId}/agent/runs?page=${page}`),
  getRun: (id: string) =>
    request<ApiResponse<AgentRun>>(`/agent-runs/${id}`),
};

// --- Subscriptions ---

