   174→
   175→Create the new activity feed that merges releases and semantic releases chronologically.
   176→
   177→**Files:**
   178→- Create: `web/components/dashboard/unified-feed.tsx`
   179→
   180→**Step 1: Create the component**
   181→
   182→```tsx
   183→// web/components/dashboard/unified-feed.tsx
   184→"use client";
   185→
   186→import useSWR from "swr";
   187→import Link from "next/link";
   188→import {
   189→  projects as projectsApi,
   190→  releases as releasesApi,
   191→  sources as sourcesApi,
   192→  semanticReleases as srApi,
   193→} from "@/lib/api/client";
   194→import { VersionChip } from "@/components/ui/version-chip";
   195→import { getProviderIcon } from "@/components/ui/provider-badge";
   196→import { Sparkles } from "lucide-react";
   197→import type { Release, SemanticRelease, Source } from "@/lib/api/types";
   198→import { timeAgo } from "@/lib/format";
   199→
   200→type FeedItemType =
   201→  | { kind: "release"; data: Release; repository?: string; provider?: string; projectName?: string }
   202→  | { kind: "semantic"; data: SemanticRelease; projectName?: string };
   203→
   204→function getTimestamp(item: FeedItemType): number {
   205→  if (item.kind === "release") {
   206→    return new Date(item.data.released_at ?? item.data.created_at).getTime();
   207→  }
   208→  return new Date(item.data.created_at).getTime();
   209→}
   210→
   211→function getTimeStr(item: FeedItemType): string {
   212→  if (item.kind === "release") {
   213→    return item.data.released_at ?? item.data.created_at;
   214→  }
   215→  return item.data.created_at;
   216→}
   217→
   218→export function UnifiedFeed() {
   219→  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
   220→    projectsApi.list()
   221→  );
   222→
   223→  const { data: feedItems, isLoading } = useSWR(
   224→    projectsData ? "unified-feed" : null,
   225→    async () => {
   226→      if (!projectsData?.data?.length) return [];
   227→
   228→      const projectMap = new Map(
   229→        projectsData.data.map((p) => [p.id, p.name])
   230→      );
   231→      const projectSlice = projectsData.data.slice(0, 10);
   232→
   233→      // Fetch releases, sources, and semantic releases in parallel
   234→      const [releaseResults, sourceResults, srResults] = await Promise.all([
   235→        Promise.all(
   236→          projectSlice.map((p) =>
   237→            releasesApi.listByProject(p.id, 1).catch(() => null)
   238→          )
   239→        ),
   240→        Promise.all(
   241→          projectSlice.map((p) =>
   242→            sourcesApi.listByProject(p.id, 1).catch(() => null)
   243→          )
   244→        ),
   245→        Promise.all(
   246→          projectSlice.map((p) =>
   247→            srApi.list(p.id, 1).catch(() => null)
   248→          )
   249→        ),
   250→      ]);
   251→
   252→      // Build source lookup maps
   253→      const sourceMap = new Map<string, string>();
   254→      const providerMap = new Map<string, string>();
   255→      const sourceProjectMap = new Map<string, string>();
   256→      sourceResults
   257→        .filter((r): r is NonNullable<typeof r> => r !== null)
   258→        .flatMap((r) => r.data)
   259→        .forEach((s: Source) => {
   260→          sourceMap.set(s.id, s.repository);
   261→          providerMap.set(s.id, s.provider);
   262→          sourceProjectMap.set(s.id, s.project_id);
   263→        });
   264→
   265→      // Build feed items
   266→      const items: FeedItemType[] = [];
   267→
   268→      releaseResults
   269→        .filter((r): r is NonNullable<typeof r> => r !== null)
   270→        .flatMap((r) => r.data)
   271→        .forEach((rel) => {
   272→          const projectId = sourceProjectMap.get(rel.source_id);
   273→          items.push({
   274→            kind: "release",
   275→            data: rel,
   276→            repository: sourceMap.get(rel.source_id),
   277→            provider: providerMap.get(rel.source_id),
   278→            projectName: projectId ? projectMap.get(projectId) : undefined,
   279→          });
   280→        });
   281→
   282→      srResults
   283→        .filter((r): r is NonNullable<typeof r> => r !== null)
   284→        .flatMap((r) => r.data)
   285→        .forEach((sr) => {
   286→          items.push({
   287→            kind: "semantic",
   288→            data: sr,
   289→            projectName: projectMap.get(sr.project_id),
   290→          });
   291→        });
   292→
   293→      // Sort by timestamp descending, take first 15
   294→      items.sort((a, b) => getTimestamp(b) - getTimestamp(a));
   295→      return items.slice(0, 15);
   296→    }
   297→  );
   298→
   299→  if (isLoading) {
   300→    return (
   301→      <div
   302→        className="rounded-lg bg-white py-16 text-center"
   303→        style={{ border: "1px solid #e8e8e5" }}
   304→      >
   305→        <p
   306→          style={{
   307→            fontFamily: "var(--font-dm-sans)",
   308→            fontSize: "13px",
   309→            color: "#6b7280",
   310→          }}
   311→        >
   312→          Loading activity...
   313→        </p>
   314→      </div>
   315→    );
   316→  }
   317→
   318→  if (!feedItems || feedItems.length === 0) {
   319→    return null; // Empty state handled by parent
   320→  }
   321→
   322→  return (
   323→    <div
   324→      className="rounded-lg bg-white"
   325→      style={{ border: "1px solid #e8e8e5" }}
   326→    >
   327→      {/* Header */}
   328→      <div
   329→        className="flex items-center justify-between px-5 py-4"
   330→        style={{ borderBottom: "1px solid #e8e8e5" }}
   331→      >
   332→        <h3
   333→          className="font-medium"
   334→          style={{
   335→            fontFamily: "var(--font-dm-sans)",
   336→            fontSize: "13px",
   337→            color: "#111113",
   338→          }}
   339→        >
   340→          Recent Activity
   341→        </h3>
   342→        <Link
   343→          href="/releases"
   344→          className="text-sm hover:underline"
   345→          style={{
   346→            fontFamily: "var(--font-dm-sans)",
   347→            fontSize: "13px",
   348→            color: "#e8601a",
   349→          }}
   350→        >
   351→          View all &rarr;
   352→        </Link>
   353→      </div>
   354→
   355→      {/* Feed items */}
   356→      <div>
   357→        {feedItems.map((item, idx) => (
   358→          <FeedEntry
   359→            key={item.kind === "release" ? `r-${item.data.id}` : `sr-${item.data.id}`}
   360→            item={item}
   361→            isLast={idx === feedItems.length - 1}
   362→          />
   363→        ))}
   364→      </div>
   365→    </div>
   366→  );
   367→}
   368→
   369→function FeedEntry({ item, isLast }: { item: FeedItemType; isLast: boolean }) {
   370→  if (item.kind === "semantic") {
   371→    const sr = item.data;
   372→    const urgency = sr.report?.urgency?.toUpperCase();
   373→    const isUrgent = urgency === "CRITICAL" || urgency === "HIGH";
   374→
   375→    return (
   376→      <Link
   377→        href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
   378→        className="flex items-start gap-3 px-5 py-3.5 transition-colors hover:bg-[#fafaf9]"
